1	// claim-office.ts
2	
3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const COMPONENT_BASE = 25;
23	const COMPONENT_BLOCK_PREMIUM = 60;
24	
25	const ITEM_BASE_PREMIUMS: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	  rune: 25,
31	  moonstone: 25,
32	};
33	
34	function isComponentType(type: string): boolean {
35	  return ITEM_BASE_PREMIUMS[type] === COMPONENT_BASE;
36	}
37	
38	function groupItemsByType(items: Item[]): Map<string, Item[]> {
39	  const groups = new Map<string, Item[]>();
40	  for (const item of items) {
41	    const group = groups.get(item.type) ?? [];
42	    group.push(item);
43	    groups.set(item.type, group);
44	  }
45	  return groups;
46	}
47	
48	function calculateItemBase(type: string, item: Item): number {
49	  let base = ITEM_BASE_PREMIUMS[type];
50	  if (item.cursed) {
51	    base += base * 0.5;
52	  }
53	  return base;
54	}
55	
56	function calculateGroupBase(type: string, group: Item[]): number {
57	  if (isComponentType(type) && group.length === 3) {
58	    return COMPONENT_BLOCK_PREMIUM;
59	  }
60	  return group.reduce((sum, item) => sum + calculateItemBase(type, item), 0);
61	}
62	
63	function calculatePolicyBase(items: Item[]): number {
64	  const groups = groupItemsByType(items);
65	  return Array.from(groups).reduce(
66	    (total, [type, group]) => total + calculateGroupBase(type, group),
67	    0
68	  );
69	}
70	
71	export function quote(input: QuoteInput): number {
72	  const policyBase = calculatePolicyBase(input.items);
73	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
74	  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
75	}
